// Custom table renderer matching pier's prettytable format
// (⋮ U+22EE for column sep, ≖ U+2256 for line sep, 1-char padding)

use std::io::Write;

pub struct Row {
    pub cells: Vec<String>,
}

const COL_SEP: char = '\u{22EE}'; // ⋮
const LINE_SEP: char = '\u{2256}'; // ≖
const PAD: usize = 1;

pub fn print<W: Write>(out: &mut W, headers: &[&str], rows: &[Row]) {
    let ncols = headers.len();
    // Compute column widths considering multi-line cells
    // Each cell may have newlines - each line is a sub-row
    // First, split each row into sub-rows
    let mut split_rows: Vec<Vec<Vec<String>>> = Vec::with_capacity(rows.len());
    for r in rows {
        let mut cell_lines: Vec<Vec<String>> = Vec::with_capacity(ncols);
        let mut max_lines = 1;
        for c in &r.cells {
            let lines: Vec<String> = c.split('\n').map(|s| s.to_string()).collect();
            if lines.len() > max_lines {
                max_lines = lines.len();
            }
            cell_lines.push(lines);
        }
        // Convert to a list of (row_line_idx -> cells)
        let mut sub_rows: Vec<Vec<String>> = Vec::with_capacity(max_lines);
        for i in 0..max_lines {
            let mut sr: Vec<String> = Vec::with_capacity(ncols);
            for cl in &cell_lines {
                sr.push(cl.get(i).cloned().unwrap_or_default());
            }
            sub_rows.push(sr);
        }
        split_rows.push(sub_rows);
    }

    // Compute column widths
    let mut widths = vec![0usize; ncols];
    for (i, h) in headers.iter().enumerate() {
        widths[i] = display_width(h);
    }
    for sub_rows in &split_rows {
        for sr in sub_rows {
            for (i, c) in sr.iter().enumerate() {
                let w = display_width(c);
                if w > widths[i] {
                    widths[i] = w;
                }
            }
        }
    }

    // Print top separator
    write_sep(out, &widths);

    // Print header
    write_row(out, &widths, headers);

    // Print intern separator after header
    write_sep(out, &widths);

    // Print data rows
    for sub_rows in &split_rows {
        for sr in sub_rows {
            let cells_ref: Vec<&str> = sr.iter().map(|s| s.as_str()).collect();
            write_row(out, &widths, &cells_ref);
        }
    }

    // Print bottom separator
    write_sep(out, &widths);
}

fn display_width(s: &str) -> usize {
    // For ASCII content this is just chars.count() in our scenarios
    s.chars().count()
}

fn write_sep<W: Write>(out: &mut W, widths: &[usize]) {
    let total = widths.iter().sum::<usize>() + widths.len() * (PAD * 2) + (widths.len() + 1);
    let line: String = std::iter::repeat(LINE_SEP).take(total).collect();
    writeln!(out, "{}", line).unwrap();
}

fn write_row<W: Write>(out: &mut W, widths: &[usize], cells: &[&str]) {
    let mut s = String::new();
    s.push(COL_SEP);
    for (i, &w) in widths.iter().enumerate() {
        let cell = cells.get(i).unwrap_or(&"");
        let cw = display_width(cell);
        s.push(' ');
        s.push_str(cell);
        if cw < w {
            for _ in 0..(w - cw) {
                s.push(' ');
            }
        }
        s.push(' ');
        s.push(COL_SEP);
    }
    writeln!(out, "{}", s).unwrap();
}

