use serde_derive::{Deserialize, Serialize};
use snafu::{ResultExt, Snafu};
use std::collections::BTreeMap;
use std::env;
use std::fs;
use std::io;
use std::path::{Path, PathBuf};
use std::process::Command;
use structopt::StructOpt;

mod table;

#[derive(Debug, Snafu)]
pub enum PierError {
    #[snafu(display("AliasNotFound: No script found by alias {}", alias))]
    AliasNotFound { alias: String },

    #[snafu(display("AliasAlreadyExists:  {}", alias))]
    AliasAlreadyExists { alias: String },

    #[snafu(display(
        "EditorError: Failed when trying to get input from editor {}",
        source
    ))]
    EditorError { source: scrawl::error::ScrawlError },

    #[snafu(display("No scripts exist. Would you like to add a new script?"))]
    NoScriptsExist,

    #[snafu(display("No default config file found. See help for more info."))]
    NoConfigFound,

    #[snafu(display("Cannot initialize config at {}, file already exists.", path.display()))]
    ConfigInitFileExists { path: PathBuf },

    #[snafu(display("Unable to read config from file {}: {}", path.display(), source))]
    ConfigRead { source: io::Error, path: PathBuf },

    #[snafu(display("Unable to parse toml config from file {}: {}", path.display(), source))]
    ConfigParse {
        source: toml::de::Error,
        path: PathBuf,
    },

    #[snafu(display("Unable to write toml config to file {}: {}", path.display(), source))]
    ConfigWrite { source: io::Error, path: PathBuf },

    #[snafu(display("Unable to serialize toml config: {}", source))]
    ConfigSerialize { source: toml::ser::Error },
}

type Result<T> = std::result::Result<T, PierError>;

#[derive(Debug, Deserialize, Serialize, Clone)]
pub struct Script {
    pub command: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub description: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub tags: Option<Vec<String>>,
}

#[derive(Debug, Deserialize, Serialize, Default)]
pub struct Defaults {
    #[serde(skip_serializing_if = "Option::is_none")]
    pub interpreter: Option<Vec<String>>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub command_width: Option<usize>,
}

#[derive(Debug, Deserialize, Serialize, Default)]
pub struct Config {
    #[serde(default)]
    pub scripts: BTreeMap<String, Script>,
    #[serde(default)]
    pub default: Defaults,
}

// ====================== CLI =====================

#[derive(Debug, StructOpt)]
#[structopt(
    name = "pier",
    about = "A simple script management CLI",
    author = "Benjamin Scholtz, Isak Johansson",
    setting = structopt::clap::AppSettings::SubcommandsNegateReqs,
    setting = structopt::clap::AppSettings::VersionlessSubcommands
)]
struct Opts {
    /// The level of verbosity
    #[structopt(short, long, parse(from_occurrences))]
    verbose: u8,

    /// Sets a custom config file.
    ///
    /// DEFAULT PATH is otherwise determined in this order:
    ///
    /// - $PIER_CONFIG_PATH (environment variable if set)
    ///
    /// - pier.toml (in the current directory)
    ///
    /// - $XDG_CONFIG_HOME/pier/config.toml
    ///
    /// - $XDG_CONFIG_HOME/pier/config
    ///
    /// - $XDG_CONFIG_HOME/pier.toml
    ///
    /// - $HOME/.pier.toml
    ///
    /// - $HOME/.pier
    ///
    #[structopt(short = "c", long = "config-file", value_name = "path", env = "PIER_CONFIG_PATH")]
    config_file: Option<PathBuf>,

    /// The alias or name for the script.
    #[structopt(name = "alias", required = true)]
    alias: Option<String>,

    /// The positional arguments to send to script.
    #[structopt(name = "args")]
    args: Vec<String>,

    #[structopt(subcommand)]
    cmd: Option<SubCmd>,
}

#[derive(Debug, StructOpt)]
enum SubCmd {
    /// Run a script matching alias.
    #[structopt(name = "run")]
    Run {
        /// The alias or name for the script.
        alias: String,
        /// The positional arguments to send to script.
        args: Vec<String>,
    },

    /// Add a new script to config.
    #[structopt(name = "add")]
    Add {
        /// The alias or name for the script.
        #[structopt(short, long)]
        alias: String,

        /// The description for the script.
        #[structopt(short, long)]
        description: Option<String>,

        /// Set which tags the script belongs to.
        #[structopt(short, long = "tag", name = "tags")]
        tags: Option<Vec<String>>,

        /// Allows to overwrite the existing script
        #[structopt(short, long)]
        force: bool,

        /// The command/script content to be executed. If this argument is not found it will open your $EDITOR for you to enter the script into.
        command: Option<String>,
    },

    /// alias: rm - Remove a script matching alias.
    #[structopt(name = "remove", alias = "rm")]
    Remove {
        /// The alias or name for the script.
        alias: String,
    },

    /// Edit a script matching alias.
    #[structopt(name = "edit")]
    Edit {
        /// The alias or name for the script.
        alias: String,
    },

    /// Show a script matching alias.
    #[structopt(name = "show")]
    Show {
        /// The alias or name for the script.
        alias: String,
    },

    /// alias: ls - List scripts
    ///
    /// Display options are determined by priority in this order:
    ///
    /// 1. List only aliases
    ///
    /// 2. Show full command
    ///
    /// 3. Command display with (cli option)
    ///
    /// 4. Command display with (config option)
    #[structopt(name = "list", alias = "ls")]
    List {
        /// Only displays aliases of the scripts.
        #[structopt(short = "q", long = "list_aliases")]
        list_aliases: bool,

        /// Display the full command.
        #[structopt(short = "l", long = "cmd_full")]
        cmd_full: bool,

        /// The max number of characters to display from the command.
        #[structopt(short = "c", long = "cmd_width", name = "cmd-width")]
        cmd_width: Option<usize>,

        /// Filter based on tags.
        #[structopt(short = "t", long = "tag", name = "tags")]
        tags: Option<Vec<String>>,
    },

    /// alias: cp - Copy existing alias to the new one
    #[structopt(name = "copy", alias = "cp")]
    Copy {
        /// The alias of the script that will be copied.
        #[structopt(name = "from-alias")]
        from_alias: String,
        /// The new alias of the copy of the script.
        #[structopt(name = "to-alias")]
        to_alias: String,
    },

    /// alias: mv, rename - Move/rename existing alias to the new one
    #[structopt(name = "move", aliases = &["mv", "rename"])]
    Move {
        /// The alias of the script that will be moved.
        #[structopt(name = "from-alias")]
        from_alias: String,
        /// The new alias of the script.
        #[structopt(name = "to-alias")]
        to_alias: String,
        /// Allows to overwrite the existing script
        #[structopt(short, long)]
        force: bool,
    },

    /// alias: init - Add a config file.
    #[structopt(name = "config-init", alias = "init")]
    ConfigInit,
}

// =================== Config discovery ====================

fn find_config_path(cli_path: Option<PathBuf>) -> Option<PathBuf> {
    if let Some(p) = cli_path {
        return Some(p);
    }
    if let Ok(p) = env::var("PIER_CONFIG_PATH") {
        if !p.is_empty() {
            return Some(PathBuf::from(p));
        }
    }
    let local = PathBuf::from("pier.toml");
    if local.exists() {
        return Some(local);
    }
    if let Some(xdg) = dirs::config_dir() {
        let candidates = [
            xdg.join("pier/config.toml"),
            xdg.join("pier/config"),
            xdg.join("pier.toml"),
        ];
        for p in &candidates {
            if p.exists() {
                return Some(p.clone());
            }
        }
    }
    if let Some(home) = dirs::home_dir() {
        let candidates = [home.join(".pier.toml"), home.join(".pier")];
        for p in &candidates {
            if p.exists() {
                return Some(p.clone());
            }
        }
    }
    None
}

fn load_config(path: &Path) -> Result<Config> {
    let contents = fs::read_to_string(path).context(ConfigRead { path: path.to_path_buf() })?;
    let config: Config =
        toml::from_str(&contents).context(ConfigParse { path: path.to_path_buf() })?;
    Ok(config)
}

fn save_config(path: &Path, config: &Config) -> Result<()> {
    let contents = toml::to_string_pretty(config).context(ConfigSerialize)?;
    fs::write(path, contents).context(ConfigWrite { path: path.to_path_buf() })?;
    Ok(())
}

// =================== Subcommand handlers ===================

fn cmd_add(
    config_path: &Path,
    config: &mut Config,
    alias: String,
    command: Option<String>,
    description: Option<String>,
    tags: Option<Vec<String>>,
    force: bool,
) -> Result<()> {
    if !force && config.scripts.contains_key(&alias) {
        return Err(PierError::AliasAlreadyExists { alias });
    }

    let command_str = match command {
        Some(c) => c,
        None => scrawl::new().context(EditorError)?,
    };

    config.scripts.insert(
        alias.clone(),
        Script {
            command: command_str,
            description,
            tags,
        },
    );

    save_config(config_path, config)?;
    println!("Added {}", alias);
    Ok(())
}

fn cmd_remove(config_path: &Path, config: &mut Config, alias: String) -> Result<()> {
    if !config.scripts.contains_key(&alias) {
        return Err(PierError::AliasNotFound { alias });
    }
    config.scripts.remove(&alias);
    save_config(config_path, config)?;
    println!("Removed {}", alias);
    Ok(())
}

fn cmd_show(config: &Config, alias: String) -> Result<()> {
    match config.scripts.get(&alias) {
        Some(s) => {
            println!("{}", s.command);
            Ok(())
        }
        None => Err(PierError::AliasNotFound { alias }),
    }
}

fn cmd_edit(config_path: &Path, config: &mut Config, alias: String) -> Result<()> {
    let script = match config.scripts.get(&alias) {
        Some(s) => s.clone(),
        None => return Err(PierError::AliasNotFound { alias }),
    };
    let new_command = scrawl::with(&script.command).context(EditorError)?;
    let updated = Script {
        command: new_command,
        description: script.description,
        tags: script.tags,
    };
    config.scripts.insert(alias.clone(), updated);
    save_config(config_path, config)?;
    println!("Edited {}", alias);
    Ok(())
}

fn cmd_copy(
    config_path: &Path,
    config: &mut Config,
    from: String,
    to: String,
) -> Result<()> {
    if config.scripts.contains_key(&to) {
        return Err(PierError::AliasAlreadyExists { alias: to });
    }
    let script = match config.scripts.get(&from) {
        Some(s) => s.clone(),
        None => return Err(PierError::AliasNotFound { alias: from }),
    };
    config.scripts.insert(to.clone(), script);
    save_config(config_path, config)?;
    println!("Copy from alias {} to new alias {}", from, to);
    Ok(())
}

fn cmd_move(
    config_path: &Path,
    config: &mut Config,
    from: String,
    to: String,
    force: bool,
) -> Result<()> {
    if !config.scripts.contains_key(&from) {
        return Err(PierError::AliasNotFound { alias: from });
    }
    if !force && from != to && config.scripts.contains_key(&to) {
        return Err(PierError::AliasAlreadyExists { alias: to });
    }
    if !force && from == to {
        // pier behavior: even self-rename without -f errors
        return Err(PierError::AliasAlreadyExists { alias: to });
    }
    let script = config.scripts.remove(&from).unwrap();
    config.scripts.insert(to.clone(), script);
    save_config(config_path, config)?;
    println!("Move from alias {} to new alias {}", from, to);
    Ok(())
}

fn cmd_run(
    config: &Config,
    alias: String,
    args: Vec<String>,
) -> Result<i32> {
    let script = match config.scripts.get(&alias) {
        Some(s) => s,
        None => return Err(PierError::AliasNotFound { alias }),
    };
    let interp = config
        .default
        .interpreter
        .clone()
        .unwrap_or_else(|| vec!["bash".to_string(), "-c".to_string()]);

    if interp.is_empty() {
        // Match upstream panic
        panic!("index out of bounds: the len is 0 but the index is 0");
    }

    let mut cmd = Command::new(&interp[0]);
    for a in &interp[1..] {
        cmd.arg(a);
    }
    cmd.arg(&script.command);
    cmd.arg(&alias);
    for a in &args {
        cmd.arg(a);
    }
    let status = cmd.status().expect("Failed to run script");
    Ok(status.code().unwrap_or(1))
}

fn cmd_list(
    config: &Config,
    list_aliases: bool,
    cmd_full: bool,
    cli_cmd_width: Option<usize>,
    filter_tags: Option<Vec<String>>,
) -> Result<()> {
    if config.scripts.is_empty() {
        return Err(PierError::NoScriptsExist);
    }

    if list_aliases {
        for alias in config.scripts.keys() {
            println!("{}", alias);
        }
        return Ok(());
    }

    // Determine command width: -l beats -c beats config
    let width: Option<usize> = if cmd_full {
        None
    } else if cli_cmd_width.is_some() {
        cli_cmd_width
    } else {
        config.default.command_width
    };

    let mut rows: Vec<table::Row> = Vec::new();
    for (alias, script) in &config.scripts {
        // Apply tag filter
        if let Some(filter) = &filter_tags {
            let script_tags = script.tags.clone().unwrap_or_default();
            let any_match = filter.iter().any(|t| script_tags.contains(t));
            if !any_match {
                continue;
            }
        }

        let tags_str = script
            .tags
            .as_ref()
            .map(|ts| ts.join(","))
            .unwrap_or_default();

        let cmd_str = match width {
            Some(w) => {
                let bytes: Vec<char> = script.command.chars().collect();
                if bytes.len() > w {
                    bytes.iter().take(w).collect::<String>()
                } else {
                    script.command.clone()
                }
            }
            None => script.command.clone(),
        };

        let desc_str = script.description.clone().unwrap_or_default();
        rows.push(table::Row {
            cells: vec![
                alias.clone(),
                tags_str,
                cmd_str,
                desc_str,
            ],
        });
    }

    let headers = vec!["Alias", "Tags", "Command", "Description"];
    let stdout = std::io::stdout();
    let mut out = stdout.lock();
    table::print(&mut out, &headers, &rows);
    Ok(())
}

fn cmd_config_init(config_path: &Path) -> Result<()> {
    if config_path.exists() {
        return Err(PierError::ConfigInitFileExists {
            path: config_path.to_path_buf(),
        });
    }
    // Build the default hello-pier entry
    let mut config = Config::default();
    config.scripts.insert(
        "hello-pier".to_string(),
        Script {
            command: "echo Hello, Pier!".to_string(),
            description: Some("This is an example command.".to_string()),
            tags: None,
        },
    );
    save_config(config_path, &config)?;
    println!("Added hello-pier");
    Ok(())
}

// =================== main ===================

fn run() -> Result<i32> {
    let opts: Opts = Opts::from_args();

    // Resolve config path
    let cli_path = opts.config_file.clone();
    let cmd_needs_config = match &opts.cmd {
        Some(SubCmd::ConfigInit) => false,
        _ => true,
    };

    let config_path: PathBuf = if let Some(p) = find_config_path(cli_path) {
        p
    } else if let Some(SubCmd::ConfigInit) = &opts.cmd {
        // For config-init, we need a path. Use default location.
        // Since no config exists, use $HOME/.pier.toml or fail
        if let Some(home) = dirs::home_dir() {
            home.join(".pier.toml")
        } else {
            return Err(PierError::NoConfigFound);
        }
    } else {
        return Err(PierError::NoConfigFound);
    };

    match opts.cmd {
        Some(SubCmd::ConfigInit) => {
            cmd_config_init(&config_path)?;
            Ok(0)
        }
        Some(SubCmd::Add {
            alias,
            description,
            tags,
            force,
            command,
        }) => {
            let mut config = if config_path.exists() {
                load_config(&config_path)?
            } else {
                Config::default()
            };
            cmd_add(&config_path, &mut config, alias, command, description, tags, force)?;
            Ok(0)
        }
        Some(SubCmd::Remove { alias }) => {
            let mut config = load_config(&config_path)?;
            cmd_remove(&config_path, &mut config, alias)?;
            Ok(0)
        }
        Some(SubCmd::Show { alias }) => {
            let config = load_config(&config_path)?;
            cmd_show(&config, alias)?;
            Ok(0)
        }
        Some(SubCmd::Edit { alias }) => {
            let mut config = load_config(&config_path)?;
            cmd_edit(&config_path, &mut config, alias)?;
            Ok(0)
        }
        Some(SubCmd::Copy { from_alias, to_alias }) => {
            let mut config = load_config(&config_path)?;
            cmd_copy(&config_path, &mut config, from_alias, to_alias)?;
            Ok(0)
        }
        Some(SubCmd::Move { from_alias, to_alias, force }) => {
            let mut config = load_config(&config_path)?;
            cmd_move(&config_path, &mut config, from_alias, to_alias, force)?;
            Ok(0)
        }
        Some(SubCmd::List { list_aliases, cmd_full, cmd_width, tags }) => {
            let config = load_config(&config_path)?;
            cmd_list(&config, list_aliases, cmd_full, cmd_width, tags)?;
            Ok(0)
        }
        Some(SubCmd::Run { alias, args }) => {
            let config = load_config(&config_path)?;
            let exit = cmd_run(&config, alias, args)?;
            Ok(exit)
        }
        None => {
            // Top-level positional alias
            let alias = opts.alias.expect("required arg <alias>");
            let config = load_config(&config_path)?;
            let exit = cmd_run(&config, alias, opts.args)?;
            Ok(exit)
        }
    }
}

fn main() {
    match run() {
        Ok(code) => std::process::exit(code),
        Err(e) => {
            eprintln!("error: {}", e);
            std::process::exit(1);
        }
    }
}

